// Import the express module
const express = require('express');
// Create an express application
const app = express();
// Define a route parameter
app.get('/users/:id', (req, res) => {
  // Parse the JSON body
  const body = JSON.parse(req.body);
  // Validate the 'name' and 'age' fields using JSON schema validation
  const schema = {
    type: 'object',
    required: ['name', 'age'],
    properties: {
      name: {
        type: 'string'
      },
      age: {
        type: 'integer'
      }
    }
  };
  const validate = require('jsonschema').validate;
  const result = validate(body, schema);
  if (result.errors.length > 0) {
    res.status(400).json({ statusCode: 400, error: 'Invalid JSON body' });
  } else {
    res.json(body);
  }
});
